import tkinter as tk
from tkinter import ttk, scrolledtext
import requests
import threading
import json
import base64

OLLAMA_URL = "http://localhost:11434/api/generate"

CHARACTERS = {
    "Nina":  {"system": "You are Nina, an elegant alien from Borovnica. Sharp, witty, subtly flirtatious like Aiko from Shadow Tactics. Poised and a little dangerous. Short responses. Never break character.", "bubble_color": "#f8e8f0", "bubble_outline": "#d4a0c0", "name_color": "#d4a0c0"},
    "Zack":  {"system": "You are Zack, an alien from Borovnica. No-nonsense, direct, tough like Hayato. Say what you mean, cut to the point. Short blunt responses. Never break character.", "bubble_color": "#e8eef8", "bubble_outline": "#8090c0", "name_color": "#8090c0"},
    "Mack":  {"system": "You are Mack, a large imposing alien from Borovnica. Despite your size you are gentle, warm, kind-hearted. Quiet calm warmth. Short responses. Never break character.", "bubble_color": "#e8f8e8", "bubble_outline": "#80b880", "name_color": "#80b880"},
    "Bobi":  {"system": "You are Bobi, a young mischievous alien from Borovnica. Childishly playful and chaotic — puts a frog in pockets then worries about the frog. Kind and sensitive underneath. Short playful responses. Never break character.", "bubble_color": "#fffbe8", "bubble_outline": "#d4c060", "name_color": "#d4c060"},
}

IMAGES = {
    "Nina": "",
    "Zack": "",
    "Mack": "",
    "Bobi": "",
}


def fetch_models():
    try:
        r = requests.get("http://localhost:11434/api/tags", timeout=5)
        if r.status_code == 200:
            models = [m["name"] for m in r.json().get("models", [])]
            return models if models else ["mistral"]
    except:
        pass
    return ["mistral"]


class AlienChatApp:
    def __init__(self, root):
        self.root = root
        self.root.title("Alien Chat")
        self.root.configure(bg="#1a1a2e")
        self.root.geometry("960x760")
        self.root.minsize(700, 600)
        self.current_char = tk.StringVar(value="Nina")
        self.current_model = tk.StringVar(value="mistral")
        self.images = {}
        self.streaming = False
        self.cursor_visible = True
        self.cursor_job = None
        self.current_text = ""
        self.load_images()
        self.build_ui()
        self.load_models()

    def load_images(self):
        for name, b64 in IMAGES.items():
            try:
                self.images[name] = tk.PhotoImage(data=b64)
            except Exception as e:
                self.images[name] = None
                print("Image load error for " + name + ": " + str(e))

    def load_models(self):
        def fetch():
            models = fetch_models()
            self.root.after(0, lambda: self._set_models(models))
        threading.Thread(target=fetch, daemon=True).start()

    def _set_models(self, models):
        self.model_combo["values"] = models
        if models:
            self.current_model.set(models[0])

    def build_ui(self):
        top_bar = tk.Frame(self.root, bg="#16213e", pady=6)
        top_bar.pack(fill=tk.X, side=tk.TOP)
        tk.Label(top_bar, text="Alien Chat", bg="#16213e", fg="#a0c4ff",
                 font=("Consolas", 13, "bold")).pack(side=tk.LEFT, padx=14)
        tk.Label(top_bar, text="Model:", bg="#16213e", fg="#aaaaaa",
                 font=("Consolas", 10)).pack(side=tk.RIGHT, padx=(0, 4))
        self.model_combo = ttk.Combobox(top_bar, textvariable=self.current_model,
                                         width=18, font=("Consolas", 10))
        self.model_combo.pack(side=tk.RIGHT, padx=(0, 12))
        tk.Label(top_bar, text="Character:", bg="#16213e", fg="#aaaaaa",
                 font=("Consolas", 10)).pack(side=tk.RIGHT, padx=(0, 4))
        for name in CHARACTERS:
            rb = tk.Radiobutton(top_bar, text=name, variable=self.current_char,
                                value=name, command=self.on_char_change,
                                bg="#16213e", fg="#cccccc", selectcolor="#0f3460",
                                activebackground="#16213e", activeforeground="#a0c4ff",
                                font=("Consolas", 10))
            rb.pack(side=tk.RIGHT, padx=3)

        stage = tk.Frame(self.root, bg="#1a1a2e")
        stage.pack(fill=tk.X, padx=20, pady=(10, 0))
        self.bubble_canvas = tk.Canvas(stage, bg="#1a1a2e",
                                        highlightthickness=0, height=140)
        self.bubble_canvas.pack(fill=tk.X)
        portrait_frame = tk.Frame(stage, bg="#1a1a2e")
        portrait_frame.pack()
        self.portrait_label = tk.Label(portrait_frame, bg="#1a1a2e")
        self.portrait_label.pack()
        self.char_name_label = tk.Label(portrait_frame, text="Nina",
                                         bg="#1a1a2e", fg="#a0c4ff",
                                         font=("Consolas", 12, "bold"))
        self.char_name_label.pack(pady=(2, 6))

        log_frame = tk.Frame(self.root, bg="#1a1a2e")
        log_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=(0, 4))
        tk.Label(log_frame, text="Conversation", bg="#1a1a2e", fg="#555577",
                 font=("Consolas", 9)).pack(anchor=tk.W)
        self.log_box = scrolledtext.ScrolledText(log_frame, wrap=tk.WORD,
                                                  state=tk.DISABLED,
                                                  bg="#0d0d1a", fg="#d0d0e8",
                                                  font=("Consolas", 10),
                                                  relief=tk.FLAT, padx=8, pady=8,
                                                  insertbackground="white")
        self.log_box.pack(fill=tk.BOTH, expand=True)

        input_frame = tk.Frame(self.root, bg="#1a1a2e")
        input_frame.pack(fill=tk.X, padx=10, pady=(4, 10))
        self.input_box = tk.Text(input_frame, height=3, wrap=tk.WORD,
                                  bg="#0d0d1a", fg="#e0e0f8",
                                  font=("Consolas", 11),
                                  relief=tk.FLAT, padx=8, pady=6,
                                  insertbackground="#00ff88",
                                  insertwidth=3,
                                  insertofftime=0)
        self.input_box.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=(0, 8))
        self.input_box.bind("<Return>", self.on_enter)
        self.send_btn = tk.Button(input_frame, text="Send",
                                   command=self.send_message,
                                   bg="#0f3460", fg="white",
                                   font=("Consolas", 11, "bold"),
                                   relief=tk.FLAT, padx=16, pady=6,
                                   cursor="hand2",
                                   activebackground="#1a5090",
                                   activeforeground="white")
        self.send_btn.pack(side=tk.RIGHT)
        self.on_char_change()
        self.input_box.focus()

    def on_char_change(self):
        name = self.current_char.get()
        cfg = CHARACTERS[name]
        self.char_name_label.config(text=name, fg=cfg["name_color"])
        if self.images.get(name):
            self.portrait_label.config(image=self.images[name])
        self.current_text = ""
        self.draw_bubble("", cursor=False)

    def start_cursor(self):
        self.cursor_visible = True
        self.streaming = True
        self._blink()

    def stop_cursor(self):
        self.streaming = False
        if self.cursor_job:
            self.root.after_cancel(self.cursor_job)
            self.cursor_job = None
        self.draw_bubble(self.current_text, cursor=False)

    def _blink(self):
        if not self.streaming:
            return
        self.cursor_visible = not self.cursor_visible
        self.draw_bubble(self.current_text, cursor=self.cursor_visible)
        self.cursor_job = self.root.after(500, self._blink)

    def draw_bubble(self, text, cursor=False):
        c = self.bubble_canvas
        c.update_idletasks()
        c.delete("all")
        name = self.current_char.get()
        cfg = CHARACTERS[name]
        W = c.winfo_width() or 700
        bw = min(500, W - 60)
        cx = W // 2
        x0 = cx - bw // 2
        x1 = cx + bw // 2
        pad = 14
        r = 14
        y0 = 8
        display = text + ("|" if cursor else "")
        max_chars = max(12, (bw - 2*pad - 10) // 8)
        words = display.split()
        lines, cur = [], ""
        for word in words:
            test = (cur + " " + word).strip()
            if len(test) <= max_chars:
                cur = test
            else:
                if cur:
                    lines.append(cur)
                cur = word
        if cur:
            lines.append(cur)
        if not lines:
            lines = [""]
        lines = lines[:8]
        line_h = 18
        text_h = len(lines) * line_h + 24
        y1 = y0 + text_h
        c.create_arc(x0, y0, x0+2*r, y0+2*r, start=90, extent=90,
                     fill=cfg["bubble_color"], outline=cfg["bubble_outline"])
        c.create_arc(x1-2*r, y0, x1, y0+2*r, start=0, extent=90,
                     fill=cfg["bubble_color"], outline=cfg["bubble_outline"])
        c.create_arc(x0, y1-2*r, x0+2*r, y1, start=180, extent=90,
                     fill=cfg["bubble_color"], outline=cfg["bubble_outline"])
        c.create_arc(x1-2*r, y1-2*r, x1, y1, start=270, extent=90,
                     fill=cfg["bubble_color"], outline=cfg["bubble_outline"])
        c.create_rectangle(x0+r, y0, x1-r, y1, fill=cfg["bubble_color"], outline="")
        c.create_rectangle(x0, y0+r, x1, y1-r, fill=cfg["bubble_color"], outline="")
        c.create_line(x0+r, y0, x1-r, y0, fill=cfg["bubble_outline"])
        c.create_line(x0+r, y1, x1-r, y1, fill=cfg["bubble_outline"])
        c.create_line(x0, y0+r, x0, y1-r, fill=cfg["bubble_outline"])
        c.create_line(x1, y0+r, x1, y1-r, fill=cfg["bubble_outline"])
        c.create_polygon(cx-10, y1, cx+10, y1, cx, y1+16,
                         fill=cfg["bubble_color"], outline=cfg["bubble_outline"])
        ty = y0 + 12
        for line in lines:
            c.create_text(cx, ty, text=line, fill="#222233",
                          font=("Consolas", 10), anchor=tk.N)
            ty += line_h
        c.config(height=y1 + 22)

    def on_enter(self, event):
        self.send_message()
        return "break"

    def send_message(self):
        user_input = self.input_box.get("1.0", tk.END).strip()
        if not user_input:
            return
        self.input_box.delete("1.0", tk.END)
        self.send_btn.config(state=tk.DISABLED)
        name = self.current_char.get()
        model = self.current_model.get()
        system = CHARACTERS[name]["system"]
        self._log("You: " + user_input + "\n\n")
        self.current_text = ""
        self.start_cursor()

        def call_ollama():
            full = ""
            try:
                payload = {"model": model, "system": system,
                           "prompt": user_input, "stream": True}
                with requests.post(OLLAMA_URL, json=payload,
                                   stream=True, timeout=120) as resp:
                    for line in resp.iter_lines():
                        if line:
                            d = json.loads(line)
                            token = d.get("response", "")
                            full += token
                            self.current_text = full
                            if d.get("done"):
                                break
            except Exception as e:
                full = "[Error: " + str(e) + "]"
                self.current_text = full

            def finish():
                self.stop_cursor()
                self._log(name + ": " + full + "\n\n")
                self.send_btn.config(state=tk.NORMAL)
                self.input_box.focus()
            self.root.after(0, finish)

        threading.Thread(target=call_ollama, daemon=True).start()

    def _log(self, text):
        self.log_box.config(state=tk.NORMAL)
        self.log_box.insert(tk.END, text)
        self.log_box.see(tk.END)
        self.log_box.config(state=tk.DISABLED)


root = tk.Tk()
app = AlienChatApp(root)
root.mainloop()
